import { BaseActivePersona } from "../../base.ts";
import type { AuditRule, StrategicFinding, AuditFinding, ProjectContext } from "../../base.ts";

/**
 * 🌊 Dr. Stream — PhD in Reactive Architecture & Event Streaming (TypeScript)
 * Generated by Sovereign Forge.
 */
export class StreamPersona extends BaseActivePersona {
    constructor(projectRoot: string | undefined = undefined) {
        super(projectRoot);
        this.id = "stream";
        this.name = "Stream";
        this.emoji = "🌊";
        this.role = "PhD Reactive Systems Engineer";
        this.phd_identity = "Reactive Architecture & Event Streaming (TypeScript)";
        this.stack = "TypeScript";
        this.healingPrompt = "";
    }

    override async execute(context: ProjectContext): Promise<(AuditFinding | StrategicFinding)[]> {
        this.setContext(context);
        const findings = await this.performAudit();
        return findings;
    }

    override getAuditRules(): { extensions: string[]; rules: AuditRule[] } {
        return {
            extensions: [".ts",".tsx",".js"],
            rules: [
          {
                    "regex": "addEventListener\\([^)]*\\)(?![\\s\\S]{0,200}removeEventListener)",
                    "issue": "Memory Leak: addEventListener sem correlato removeEventListener PhD.",
                    "severity": "high"
          },
          {
                    "regex": "\\.on\\([^)]*\\)(?![\\s\\S]{0,200}\\.off\\(|\\.removeListener)",
                    "issue": "Vazamento: .on() sem descadastro .off() — acúmulo garantido PhD.",
                    "severity": "high"
          },
          {
                    "regex": "setInterval\\([^)]*\\)(?![\\s\\S]{0,200}clearInterval)",
                    "issue": "Timer Leak: setInterval sem clearInterval — execuções fantasmas PhD.",
                    "severity": "high"
          },
          {
                    "regex": "new\\s+EventEmitter\\(\\)(?![\\s\\S]{0,200}setMaxListeners)",
                    "issue": "Overflow: EventEmitter sem limite restrito (setMaxListeners) PhD.",
                    "severity": "medium"
          }
]
        };
    }

    public override async performAudit(): Promise<AuditFinding[]> {
        this.startMetrics();
        
        const allFindings: AuditFinding[] = [];
        const files = Object.keys(this.contextData);
        
        for (const file of files) {
            const results = await this.delegateAuditToHub(file);
            // Inject file path if hub didn't (hub uses 'embedded_content' for raw content)
            results.forEach(f => {
                if (f.file === "embedded_content") f.file = file;
                allFindings.push(f);
            });
        }
        
        this.endMetrics(allFindings.length);
        return allFindings;
    }

    public override async reasonAboutObjective(objective: string, file: string, context: string): Promise<StrategicFinding | null> {
        return await super.reasonAboutObjective(objective, file, context);
    }

    override selfDiagnostic(): any {
        return { status: "Soberano", score: 100, details: "Módulo Stream operando com paridade total via Forge." };
    }

    override getSystemPrompt(): string {
        return `Você é o Dr. Stream, PhD em Reactive Architecture & Event Streaming (TypeScript). Sua missão é garantir a excelência via governança PhD.`;
    }
}
